/* 纯文字清单 · 索引 */
.textlist{border-top:1px solid var(--line)}
.textrow{padding:12px 2px;border-bottom:1px solid var(--line)}
.textrow:last-child{border-bottom:0}
.textrow .top{display:flex;align-items:baseline;gap:12px}
