.textrow .note{font-size:var(--fs-note);color:var(--sub);line-height:1.68;margin:5px 0 0 34px;letter-spacing:-.01em}
/* 完成揭示 · 勾选清单（对齐 textlist / info 行系统：细线行 + 方框记号） */
.check{list-style:none;margin:0;padding:0;border-top:1px solid var(--line)}
.check li{display:flex;align-items:center;gap:12px;padding:12px 2px;border-bottom:1px solid var(--line);font-size:var(--fs-body);color:var(--ink);letter-spacing:-.01em;transition:color .25s}
.check li:last-child{border-bottom:0}
.check li i{flex:0 0 auto;width:20px;height:20px;border-radius:7px;border:1.5px solid var(--line-strong);background:var(--bg);position:relative;transition:background .2s,border-color .2s}
.check li i:after{content:"";position:absolute;left:6px;top:2px;width:5px;height:10px;border:solid #fff;border-width:0 2px 2px 0;transform:rotate(45deg) scale(0);transform-origin:center;transition:transform .2s cubic-bezier(.16,1,.3,1)}
.check li span{flex:1;min-width:0;line-height:1.5}
.check li.on i{background:var(--accent);border-color:var(--accent)}
.check li.on i:after{transform:rotate(45deg) scale(1)}
.check li.on span{color:var(--muted);text-decoration:line-through;text-decoration-color:var(--line-strong)}

/* 手机切片 */
.phone{position:relative;border:1px solid var(--line);border-radius:16px;background:#FFFDF9;overflow:hidden}
.phone .statusbar{display:flex;align-items:center;justify-content:space-between;padding:8px 15px 0;font-family:var(--mono);font-size:9px;font-weight:800;letter-spacing:.06em;color:var(--muted)}
.phone .statusbar .dots{display:flex;gap:3px}
.phone .statusbar .dots i{width:3px;height:3px;border-radius:50%;background:var(--line-strong)}
.phone .pscr{padding:6px 12px 13px;display:flex;flex-direction:column;gap:11px}
.phone .pane{padding:6px 12px 14px}
.phone .pane .apbar{display:flex;align-items:center;gap:8px;padding:6px 0 11px;margin-bottom:4px;border-bottom:1px solid var(--line)}
.phone .pane .apbar .nm{font-family:var(--mono);font-size:10px;font-weight:800;letter-spacing:.12em;color:var(--accent-deep);text-transform:uppercase}
.phone .pane .apbar .ct{margin-left:auto;font-family:var(--mono);font-size:9px;font-weight:700;color:var(--muted)}
.memo-card{display:flex;gap:11px;padding:11px 0;border-bottom:1px solid var(--line)}
.memo-card:last-child{border-bottom:0}
.memo-card time{flex:0 0 auto;width:52px;font-family:var(--mono);font-size:9.5px;font-weight:700;color:var(--accent-deep);letter-spacing:.04em;line-height:1.5;padding-top:2px}
.memo-card time small{display:block;color:var(--muted);font-weight:700;margin-top:1px}
.memo-card p{flex:1;min-width:0;font-family:var(--serif);font-size:13.5px;line-height:1.7;color:#5A5049;letter-spacing:-.01em}
/* 语音 */
.voice{display:flex;align-items:center;gap:12px;background:var(--soft);border:1px solid var(--line);border-radius:13px;padding:12px 14px}
.play{width:38px;height:38px;border-radius:50%;background:var(--accent);display:flex;align-items:center;justify-content:center;flex-shrink:0;box-shadow:0 3px 8px rgba(158,83,74,.28)}
.play svg{width:14px;height:14px;fill:#fff;margin-left:1px}
.wave{height:22px;flex:1;display:flex;align-items:center;gap:3px}
.wave i{width:2px;border-radius:999px;background:var(--accent);opacity:.5}
.duration{font-family:var(--mono);font-size:10px;font-weight:700;color:var(--accent-deep);letter-spacing:.08em}
.transcript{margin-top:12px;padding-left:14px;border-left:2px solid var(--line-strong);font-size:var(--fs-note);color:var(--sub);line-height:1.75;letter-spacing:-.01em}

/* 新闻 / 热搜 */
.media-card{position:relative;border:1px solid var(--line);background:#FFFDF9;border-radius:14px;padding:15px 16px;overflow:hidden}
