.media-kicker{display:flex;align-items:center;gap:8px;margin-bottom:10px}
.media-kicker .cat{font-family:var(--mono);font-size:8.5px;font-weight:800;letter-spacing:.12em;color:var(--accent-deep);background:var(--accent-soft);border-radius:5px;padding:3px 7px}
.media-kicker .tm{margin-left:auto;font-family:var(--mono);font-size:var(--fs-en);font-weight:700;color:var(--muted);letter-spacing:.08em}
.media-title{font-size:14.5px;font-weight:800;line-height:1.52;color:var(--ink);letter-spacing:-.02em;margin-bottom:8px}
.media-body{font-size:var(--fs-note);color:var(--sub);line-height:1.75;letter-spacing:-.01em}
.media-src{display:flex;align-items:center;gap:7px;margin-top:11px;padding-top:10px;border-top:1px solid var(--line);font-family:var(--mono);font-size:9px;font-weight:700;color:var(--muted);letter-spacing:.06em}
.media-src .src-dot{width:5px;height:5px;border-radius:50%;background:var(--accent)}
.rank-row{display:flex;align-items:center;gap:12px;padding:11px 2px;border-bottom:1px solid var(--line);font-size:var(--fs-body);color:var(--ink);letter-spacing:-.01em}
.rank-row:last-child{border-bottom:0}
.rank-row .num{font-family:var(--mono);font-size:11px;font-weight:800;color:var(--muted);width:18px;height:18px;border-radius:6px;display:flex;align-items:center;justify-content:center;background:var(--soft);flex:0 0 auto}
.rank-row.hot .num{color:#fff;background:var(--accent)}
.rank-row .kw{flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.rank-row .heat{margin-left:auto;font-family:var(--mono);font-size:10px;font-weight:700;color:var(--muted);white-space:nowrap}
.rank-row.hot .heat{color:var(--accent-deep)}
.rank-row .flame{font-family:var(--mono);font-size:8px;font-weight:800;color:#fff;background:var(--accent-deep);border-radius:4px;padding:2px 5px;letter-spacing:.08em;white-space:nowrap}

/* 评论 */
.comment-stack{border-top:1px solid var(--line)}
.comment{display:flex;gap:12px;padding:14px 2px;border-bottom:1px solid var(--line)}
.comment:last-child{border-bottom:0}
.avatar{width:30px;height:30px;border-radius:50%;display:flex;align-items:center;justify-content:center;flex-shrink:0;font-family:var(--mono);font-size:9px;font-weight:780;letter-spacing:.02em;background:var(--accent-soft);color:var(--accent-deep)}
.avatar.gray{background:#EEE9E0;color:#8C8378}.avatar.dark{background:#E6E1D6;color:#6B6357}
