.comment .rolechip{font-family:var(--mono);font-size:9px;font-weight:700;color:var(--muted);letter-spacing:.1em}
.comment p{font-size:12.5px;color:var(--sub);line-height:1.72;margin-top:4px;letter-spacing:-.01em}
.comment .like{font-family:var(--mono);font-size:10px;color:var(--muted);margin-top:6px;letter-spacing:.1em}
.comment .like:before{content:"\2661 "}

/* 论坛体 · 盖楼帖 */
.forum{border:1px solid var(--line);border-radius:14px;overflow:hidden;background:#FFFDF9}
.forum .fhead{padding:13px 15px;background:var(--soft);border-bottom:1px solid var(--line)}
.forum .fboard{display:flex;align-items:center;gap:7px;font-family:var(--mono);font-size:9px;font-weight:700;color:var(--muted);letter-spacing:.1em}
.forum .fboard:before{content:"";width:11px;height:11px;border-radius:3px;background:var(--accent-soft);border:1px solid #E7C7BF}
.forum .ftitle{font-size:13.5px;font-weight:800;color:var(--ink);letter-spacing:-.01em;line-height:1.5;margin-top:8px}
.forum .fstat{display:flex;gap:14px;margin-top:8px;font-family:var(--mono);font-size:9px;font-weight:700;color:var(--muted);letter-spacing:.06em}
.forum .fstat span:before{content:attr(data-k);color:var(--line-strong);margin-right:4px}
.forum .fpost{display:flex;gap:11px;padding:13px 15px;border-bottom:1px solid var(--line)}
.forum .fpost:last-child{border-bottom:0}
.forum .fpost.op{background:#FEFCF6}
.forum .fav{width:30px;height:30px;border-radius:9px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-family:var(--mono);font-size:9px;font-weight:780;background:var(--accent-soft);color:var(--accent-deep)}
.forum .fav.g{background:#EEE9E0;color:#8C8378}.forum .fav.d{background:#E6E1D6;color:#6B6357}
.forum .fbd{flex:1;min-width:0}
.forum .fmeta{display:flex;align-items:baseline;gap:7px}
.forum .fname{font-size:12px;font-weight:780;color:var(--ink);letter-spacing:-.01em}
.forum .ftag{font-family:var(--mono);font-size:8px;font-weight:700;color:var(--accent-deep);background:var(--accent-soft);border-radius:5px;padding:1px 5px;letter-spacing:.06em}
.forum .ffloor{margin-left:auto;font-family:var(--mono);font-size:9px;font-weight:700;color:var(--muted);letter-spacing:.04em}
.forum .ftext{font-size:12.5px;color:var(--sub);line-height:1.72;margin-top:5px;letter-spacing:-.01em}
.forum .fquote{margin-top:7px;padding:7px 10px;border-left:2px solid var(--line-strong);background:var(--soft);border-radius:0 7px 7px 0;font-size:11px;color:var(--muted);line-height:1.6}
.forum .fquote b{color:var(--sub);font-weight:700}
.forum .ffoot{display:flex;gap:14px;margin-top:8px;font-family:var(--mono);font-size:9px;font-weight:700;color:var(--muted);letter-spacing:.06em}
.forum .ffoot .up:before{content:"\2661 "}
.forum .ffoot .re:before{content:"\21A9 "}

/* Q&A */
.qa{border-top:1px solid var(--line)}
.qa-row{padding:13px 0;border-bottom:1px solid var(--line)}
.qa-row:last-child{border-bottom:0}
.q{font-size:13px;font-weight:800;color:var(--ink);letter-spacing:-.01em;line-height:1.55}
.q .qmark{font-family:var(--mono);font-size:11px;color:var(--accent-deep);margin-right:6px;letter-spacing:.08em}
.a{font-size:12.5px;color:var(--sub);line-height:1.78;margin-top:7px;letter-spacing:-.01em;padding-left:22px}

/* 时间线 · 竖向 */
.tl{position:relative;padding-left:20px}
.tl:before{content:"";position:absolute;left:3px;top:5px;bottom:5px;width:1px;background:var(--line-strong)}
.tl-row{position:relative;padding-bottom:18px}
.tl-row:last-child{padding-bottom:0}
.tl-row:before{content:"";position:absolute;left:-20px;top:4px;width:7px;height:7px;border-radius:50%;background:var(--bg);border:1.5px solid var(--accent);box-shadow:0 0 0 3px var(--bg)}
.tl-date{font-family:var(--mono);font-size:10px;font-weight:700;letter-spacing:.1em;color:var(--accent-deep)}
.tl-t{font-size:13px;font-weight:800;color:var(--ink);margin:3px 0 4px;letter-spacing:-.01em}
.tl-x{font-size:var(--fs-note);color:var(--sub);line-height:1.72;letter-spacing:-.01em}

/* 规则说明块 */
.stage-card{background:var(--stage);color:var(--stage-tx);border-radius:14px;padding:16px}
.stage-card .st{font-family:var(--mono);font-size:var(--fs-en);font-weight:700;letter-spacing:.18em;color:#E7C4BC;text-transform:uppercase;margin-bottom:9px}
.stage-card p{font-size:12.5px;color:var(--stage-sub);line-height:1.85;letter-spacing:-.01em}

/* 通话记录行（手机一角皮肤） */
