.call-av.fam{background:var(--accent-soft);border-color:#E7C7BF;color:var(--accent-deep)}
.call-av.pet{background:#EFEAD9;border-color:#E0D6BF;color:var(--gold)}
.call-av.you{background:var(--accent-deep);border-color:var(--accent-deep);color:#fff}
.call-bd{flex:1;min-width:0}
.call-nm{font-size:13.5px;font-weight:800;color:var(--ink);letter-spacing:-.01em}
