<!-- ========== 脚本：头图视差（保留） + 交互（按选中的 A/B/C 保留对应一段） ========== -->
<script>
/* 头图视差 sheen —— 氛围，非叙事互动，始终保留 */
(function(){
  if(matchMedia("(prefers-reduced-motion:reduce)").matches)return;
  var p=document.querySelector(".photo");if(!p)return;
  p.addEventListener("pointermove",function(e){
    var r=p.getBoundingClientRect(),x=(e.clientX-r.left)/r.width,y=(e.clientY-r.top)/r.height;
    p.classList.add("live");
    p.style.setProperty("--ry",((x-.5)*7).toFixed(2)+"deg");
    p.style.setProperty("--rx",((.5-y)*7).toFixed(2)+"deg");
    p.style.setProperty("--sx",(x*100).toFixed(1)+"%");
    p.style.setProperty("--sy",(y*100).toFixed(1)+"%");
  });
  p.addEventListener("pointerleave",function(){p.classList.remove("live");
    p.style.setProperty("--ry","0deg");p.style.setProperty("--rx","0deg");});
})();
</script>

<!-- 【A】完成揭示脚本 -->
<script>
(function(){
  var ul=document.getElementById("cl");if(!ul)return;
  var bar=document.getElementById("progBar"),tx=document.getElementById("progTx"),rv=document.getElementById("rv");
  var ticks=[].slice.call(ul.querySelectorAll("[data-tick]")),total=ticks.length;
  function upd(){
    var n=ul.querySelectorAll("[data-tick].on").length;
    if(bar)bar.style.width=(n/total*100)+"%";
    if(n>=total){if(tx)tx.textContent="全部完成 ✓";if(rv)rv.classList.add("on");}
    else if(tx)tx.textContent="还差 "+(total-n)+" 项 · 点上面的方框";
  }
  ticks.forEach(function(li){li.addEventListener("click",function(){li.classList.toggle("on");upd();});});
  upd();
})();
</script>

<!-- 【B】探索揭示脚本 -->
<script>
(function(){
  var wrap=document.getElementById("flips");if(!wrap)return;
  var rv=document.getElementById("rv"),cards=[].slice.call(wrap.querySelectorAll(".flip")),flipped={},n=cards.length;
  cards.forEach(function(c){
    c.addEventListener("click",function(){
      var f=c.querySelector(".fin");
      var on=c.getAttribute("data-on")==="1";c.setAttribute("data-on",on?"0":"1");
      f.style.transform=on?"":"rotateY(180deg)";
      flipped[c.dataset.i]=!on;
      var cnt=Object.keys(flipped).filter(function(k){return flipped[k];}).length;
      if(cnt>=n&&rv)rv.classList.add("on");
    });
  });
})();
</script>

</body>
</html>

